import{_ as r,c as o,o as n,ag as s}from"./chunks/framework.XjE0kKti.js";const d="/gatewayweb/docs/assets/hub0082-alert-log-list.CYbM3KKz.png",a="/gatewayweb/docs/assets/hub0082-alert-log-context-menu.Jdk4hmhy.png",p=JSON.parse('{"title":"预警日志管理（hub0082）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0082.md","filePath":"modules/hub0082.md","lastUpdated":null}'),g={name:"modules/hub0082.md"};function e(h,t,l,i,b,u){return n(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="预警日志管理-hub0082" tabindex="-1">预警日志管理（hub0082） <a class="header-anchor" href="#预警日志管理-hub0082" aria-label="Permalink to &quot;预警日志管理（hub0082）&quot;">​</a></h1><p>查询系统中已记录或已投递的 <strong>预警（告警）日志</strong>：可按时间范围、日志 ID、级别、类型、标题、渠道与发送状态筛选；列表支持分页、勾选批量删除、右键查看详情与单行删除；详情弹窗展示完整字段及 JSON 扩展数据。</p><p><img src="'+d+'" alt="预警日志列表与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>条件查询</td><td><strong>时间范围</strong> 为必填；其它条件为空时不参与过滤。</td></tr><tr><td>列表展示</td><td>展示日志 ID、级别、类型、标题、内容、渠道、发送状态及时间等；支持底部分页。</td></tr><tr><td>批量删除</td><td>工具栏 <strong>删除</strong>：需先在表格左侧 <strong>勾选</strong> 一条或多条记录，确认后批量删除。未勾选时会提示先选择。</td></tr><tr><td>单行操作</td><td>表格 <strong>右键菜单</strong>：复制行数据、复制单元格（表格内置）、<strong>查看详情</strong>、<strong>删除</strong>（当前行）。</td></tr></tbody></table><p>与 <strong><a href="./hub0080.html">预警服务配置（hub0080）</a></strong> 中维护的 <strong>渠道名称</strong> 对应：日志中的「渠道名称」即发送时所选用的渠道标识。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>预警管理</strong> → <strong>预警日志管理</strong>。</p><hr><h2 id="列表与筛选" tabindex="-1">列表与筛选 <a class="header-anchor" href="#列表与筛选" aria-label="Permalink to &quot;列表与筛选&quot;">​</a></h2><h3 id="时间范围-必填" tabindex="-1">时间范围（必填） <a class="header-anchor" href="#时间范围-必填" aria-label="Permalink to &quot;时间范围（必填）&quot;">​</a></h3><ul><li>控件为 <strong>日期时间范围</strong>；打开页面时默认 <strong>当天 00:00:00～23:59:59</strong>。</li><li>面板内提供快捷选项：<strong>今天</strong>、<strong>昨天</strong>、<strong>最近 1 小时</strong>、<strong>最近 6 小时</strong>、<strong>最近 24 小时</strong>、<strong>最近 7 天</strong>。</li><li>未选择完整起止时间时，查询会校验并提示选择时间范围。</li></ul><h3 id="其它筛选项" tabindex="-1">其它筛选项 <a class="header-anchor" href="#其它筛选项" aria-label="Permalink to &quot;其它筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>日志 ID</strong></td><td>占位：请输入日志 ID。</td></tr><tr><td><strong>告警级别</strong></td><td>全部 / <strong>信息</strong> / <strong>警告</strong> / <strong>错误</strong> / <strong>严重</strong>。</td></tr><tr><td><strong>告警类型</strong></td><td>占位：请输入告警类型（业务自定义类型标识）。</td></tr><tr><td><strong>告警标题</strong></td><td>占位：请输入告警标题。</td></tr><tr><td><strong>渠道名称</strong></td><td>占位：请输入渠道名称。</td></tr><tr><td><strong>发送状态</strong></td><td>全部 / <strong>待发送</strong> / <strong>发送中</strong> / <strong>成功</strong> / <strong>失败</strong>。</td></tr></tbody></table><p><strong>查询</strong> 按当前条件刷新列表（会重置到第一页）。<strong>重置</strong> 清空条件并恢复表单默认值（含当天时间范围）。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>删除</strong></td><td><strong>批量删除</strong>：仅处理 <strong>已勾选</strong> 的行；确认后按选中条数批量删除。</td></tr></tbody></table><hr><h2 id="表格列" tabindex="-1">表格列 <a class="header-anchor" href="#表格列" aria-label="Permalink to &quot;表格列&quot;">​</a></h2><p>除左侧 <strong>勾选列</strong> 与 <strong>序号</strong> 外，主要数据列包括：</p><table tabindex="0"><thead><tr><th>列名</th><th>说明</th></tr></thead><tbody><tr><td><strong>日志 ID</strong></td><td>日志主键。</td></tr><tr><td><strong>告警级别</strong></td><td>以标签展示：信息 / 警告 / 错误 / 严重。</td></tr><tr><td><strong>告警类型</strong></td><td>类型标识。</td></tr><tr><td><strong>告警标题</strong></td><td>摘要标题。</td></tr><tr><td><strong>告警内容</strong></td><td>正文，过长时悬停可看完整内容。</td></tr><tr><td><strong>渠道名称</strong></td><td>发送使用的渠道。</td></tr><tr><td><strong>发送状态</strong></td><td>待发送 / 发送中 / 成功 / 失败。</td></tr><tr><td><strong>告警时间</strong></td><td>告警发生时间。</td></tr><tr><td><strong>发送时间</strong></td><td>实际发送时间（若有）。</td></tr><tr><td><strong>错误信息</strong></td><td>发送失败时的错误说明。</td></tr><tr><td><strong>创建时间 / 创建人</strong></td><td>记录写入信息。</td></tr><tr><td><strong>修改时间 / 修改人</strong></td><td>最后变更信息。</td></tr></tbody></table><hr><h2 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h2><p>在表格数据行上 <strong>右键</strong> 可打开上下文菜单（含表格内置复制项）：</p><p><img src="'+a+'" alt="预警日志表格右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据</strong></td><td>将当前行各列数据复制到剪贴板（表格内置）。</td></tr><tr><td><strong>复制单元格</strong></td><td>复制右键所指向单元格的内容（表格内置）。</td></tr><tr><td><strong>查看详情</strong></td><td>打开 <strong>预警日志详情</strong> 弹窗，按日志 ID 拉取完整记录。</td></tr><tr><td><strong>删除</strong></td><td>删除 <strong>当前右键所在行</strong> 对应日志，需二次确认。</td></tr></tbody></table><hr><h2 id="详情弹窗" tabindex="-1">详情弹窗 <a class="header-anchor" href="#详情弹窗" aria-label="Permalink to &quot;详情弹窗&quot;">​</a></h2><ul><li>标题形如：<strong>预警日志详情 -</strong> 后跟当前 <strong>日志 ID</strong>。</li><li><strong>基本信息</strong>：日志 ID、告警级别、告警类型、渠道名称、告警时间、发送状态、发送时间、创建与修改信息、错误信息等。</li><li><strong>告警标题</strong>、<strong>告警内容</strong>：若有则单独卡片展示。</li><li><strong>扩展数据</strong>：当存在告警标签、额外数据、表格数据或发送结果等 JSON 字段时，以折叠面板展示，并支持格式化查看。</li></ul><p>弹窗无底部按钮栏，通过右上角关闭；关闭后列表不会自动刷新，若需看到最新状态请再次 <strong>查询</strong>。</p>',32)])])}const m=r(g,[["render",e]]);export{p as __pageData,m as default};
